document.addEventListener('DOMContentLoaded',function(){const menuToggle=document.querySelector('.menu-toggle');const navContainer=document.querySelector('.nav-container');if(menuToggle && navContainer){menuToggle.addEventListener('click',function(){navContainer.classList.toggle('active');menuToggle.setAttribute('aria-expanded',navContainer.classList.contains('active')? 'true':'false');});}initConsultationForms();initSmoothScroll();initStickyHeader();});function initConsultationForms(){const forms=document.querySelectorAll('form');forms.forEach(form=>{const channelInputs=Array.from(form.querySelectorAll('input[name="communication_channels[]"]'));if(channelInputs.length){updateChannelFields(form);channelInputs.forEach(input=>{input.addEventListener('change',()=>updateChannelFields(form));});}form.addEventListener('submit',function(event){const honeypot=form.querySelector('input[name="website"],input[name="company_url"]');if(honeypot && honeypot.value){event.preventDefault();return false;}const email=form.querySelector('input[name="email"]');const emailConfirm=form.querySelector('input[name="email_confirm"]');if(email && emailConfirm && email.value !==emailConfirm.value){event.preventDefault();alert('Die E-Mail-Adressen stimmen nicht überein. Bitte überprüfen Sie Ihre Eingabe.');emailConfirm.focus();return false;}if(channelInputs.length && !hasTwoValidChannels(form)){event.preventDefault();alert('Bitte wählen Sie mindestens zwei Kontaktkanäle aus und füllen Sie die passenden Kontaktdaten aus.');return false;}if(!validateRequiredFields(form)){event.preventDefault();alert('Bitte füllen Sie alle erforderlichen Felder aus.');return false;}});});}function updateChannelFields(form){const selected=selectedChannels(form);const emailField=form.querySelector('[data-channel-field="email"]');const telegramField=form.querySelector('[data-channel-field="telegram"]');const whatsappField=form.querySelector('[data-channel-field="whatsapp"]');toggleFieldGroup(emailField,selected.includes('email'));toggleFieldGroup(telegramField,selected.includes('telegram'));toggleFieldGroup(whatsappField,selected.includes('whatsapp'));}function toggleFieldGroup(group,isVisible){if(!group)return;group.hidden=!isVisible;group.querySelectorAll('input,textarea,select').forEach(input=>{if(input.dataset.requiredWhenVisible==='true'){input.required=isVisible;}});}function selectedChannels(form){return Array.from(form.querySelectorAll('input[name="communication_channels[]"]:checked')).map(input=>input.value);}function hasTwoValidChannels(form){const selected=selectedChannels(form);let valid=0;if(selected.includes('email')){const email=form.querySelector('input[name="contact_email"],input[name="email"]');if(email && email.value.trim()&& email.checkValidity())valid++;}if(selected.includes('telegram')){const telegram=form.querySelector('input[name="telegram_username"]');if(telegram && telegram.value.trim())valid++;}if(selected.includes('whatsapp')){const code=form.querySelector('input[name="whatsapp_country_code"]');const phone=form.querySelector('input[name="whatsapp_number"]');if(code && phone && code.value.trim()&& phone.value.trim())valid++;}return selected.length>=2 && valid>=2;}function validateRequiredFields(form){let isValid=true;form.querySelectorAll('[required]').forEach(field=>{const hiddenParent=field.closest('[hidden]');if(hiddenParent)return;if(!field.checkValidity()){isValid=false;field.classList.add('field-error');}else{field.classList.remove('field-error');}});return isValid;}function initSmoothScroll(){document.querySelectorAll('a[href^="#"]').forEach(anchor=>{anchor.addEventListener('click',function(event){const href=this.getAttribute('href');if(href==='#')return;const target=document.querySelector(href);if(!target)return;event.preventDefault();target.scrollIntoView({behavior:'smooth',block:'start'});});});}function initStickyHeader(){const header=document.querySelector('.header');if(!header || !('IntersectionObserver' in window))return;const sentinel=document.createElement('div');sentinel.style.cssText='position:absolute;top:0;left:0;width:1px;height:1px;pointer-events:none;';document.body.prepend(sentinel);const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{header.classList.toggle('scrolled',!entry.isIntersecting);});});observer.observe(sentinel);}